#ifndef SAMPLE_SATELLITES_H
#define SAMPLE_SATELLITES_H

#include <hubble/sat/pass_prediction.h>

#include <stddef.h>

/*
 * Satellite orbital parameters. The sats[] table is generated by
 * tools/orbital_params_fetch.py from the Hubble ephemeris API into
 * sat_params.generated.c (gitignored); the build falls back to the committed
 * all-zero sat_params.c placeholder when it is absent. That generator does not
 * emit an element count, so satellites.c wraps the table to expose sats_count.
 * Regenerate before real use.
 */
extern struct hubble_sat_orbital_params sats[];
extern const size_t sats_count;

#endif /* SAMPLE_SATELLITES_H */
